define("theme_iiidem2/curriculum_completion",[],(function(){var pending={};function init(config){if(!config||!config.ajaxurl||!config.sesskey)return;var curriculum=document.querySelector(".iiidem-curriculum");function markViewed(cmid,source){if(!cmid||pending[cmid])return;pending[cmid]=!0;var body=new URLSearchParams({sesskey:config.sesskey,cmid:cmid});fetch(config.ajaxurl,{method:"POST",credentials:"same-origin",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:body.toString()}).then((function(response){if(!response.ok)throw new Error("request failed");return response.json()})).then((function(data){if(!data||!data.success)throw new Error("completion failed");source&&source.classList.add("iiidem-curriculum-preview-btn--tracked")})).catch((function(){delete pending[cmid]}))}curriculum&&(curriculum.addEventListener("click",(function(event){var button=event.target.closest(".iiidem-curriculum-preview-btn");button&&curriculum.contains(button)&&"1"===button.getAttribute("data-trackcompletion")&&markViewed(button.getAttribute("data-cmid"),button)})),curriculum.addEventListener("shown.bs.collapse",(function(event){var panel=event.target;panel&&panel.id&&0===panel.id.indexOf("preview")&&"1"===panel.getAttribute("data-trackcompletion")&&markViewed(panel.getAttribute("data-cmid"),null)})))}return{init:init}}));
